#[derive(Debug, Clone, Copy)]
struct Distance(f64);


type Meter = Unit<f64>;

fn calculate_distance(a: f64, b: f64) -> Box<dyn std::any::Any> {
    let result = Distance(a.abs() + b.abs());
    Box::new(result)
}

fn process_measurement(input: &Meter, other: &Meter) -> Result<Box<dyn std::any::Any>, &'static str> {
    if input.type_check() != Some(std::any::type_name::<f64>()) || other.type_check() != Some(std::any::type_name::<f64>()) {
        return Err("Units do not match expected type.");
    }
    let result: Box<dyn std::any::Any> = calculate_distance(10.0, 5.0).into();
    Ok(result)
}

impl Unit<f64> {
    fn type_check(&self) -> Option<&'static str> {
        Some("Distance Marker")
    }
}

fn main() {
    let unit1 = Meter::new();
    let unit2 = Meter::new();
    match process_measurement(&unit1, &unit2) {
        Ok(result) => {
            if let Some(distance) = result.downcast_ref::<Distance>() {
                println!("Successfully calculated distance: {}", distance.0);
            }
        }
        Err(e) => {
            eprintln!("Error during calculation: {}", e);
        }
    }
}

use std::collections::HashMap;
use std::time::{Duration, Instant};

type RateMap = HashMap<String, (Instant, u32)>;

fn check_rate_limit(map: &mut RateMap, key: &str, limit: u32) -> bool {
    let now = Instant::now();
    match map.get_mut(key) {
        Some((last_check, count)) => {
            if now.duration_since(*last_check) >= Duration::from_secs(60) {
                *last_check = now;
                *count = 1;
                return true;
            }

            if *count < limit {
                *count += 1;
                true
            } else {
                false
            }
        },
        None => {
            map.insert(key.to_string(), (now, 1));
            true
        }
    }
}

fn main() {
    let mut user_counts: RateMap = HashMap::new();
    let api_key = "user_123";
    let max_requests = 5;

    println!("Attempting to check rate limit for {} (Max {}) ...", api_key, max_requests);

    for i in 0..7 {
        if check_rate_limit(&mut user_counts, api_key, max_requests) {
            println!("Request {} successful: Within rate limits.", i + 1);
        } else {
            println!("Request {} blocked: Rate limit exceeded.", i + 1);
            break;
        }
    }
}

use std::fmt::{self, Display};

struct UserId(u64);
struct TimestampedId(i64);

impl Display for UserId {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "User ID: {}", self.0)
    }
}

impl Display for TimestampedId {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "Timestamped ID: {}", self.0)
    }
}

struct ProcessedData {
    data: String,
}

fn process_item<T: std::fmt::Display + 'static>(item: T) -> Result<String, &'static str> {
    if item.to_string().contains("User ID:") {
        Ok(format!("Successfully processed user block."))
    } else if item.to_string().contains("Timestamped ID:") {
        Ok(format!("Successfully processed timestamped block."))
    } else {
        Err("Unknown data format encountered in the block.")
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let user_id = UserId(12345);
    let ts_id = TimestampedId(1678890000);

    let result1 = process_item(user_id.to_string());
    println!("Result 1: {:?}", result1);

    let result2 = process_item(ts_id.to_string());
    println!("Result 2: {:?}", result2);

    Ok(())
}
